import ast, sys
sys.stdout.reconfigure(encoding='utf-8')
with open(r'C:\Users\Revexn\CodeAnalyzer\code_analyzer.py', 'r', encoding='utf-8') as f:
    source = f.read()
tree = ast.parse(source)
for node in ast.walk(tree):
    if isinstance(node, ast.ClassDef):
        print(f'CLASS: {node.name}')
        for item in node.body:
            if isinstance(item, ast.FunctionDef):
                args = [a.arg for a in item.args.args]
                print(f'  METHOD: {item.name}({', '.join(args)})')
    elif isinstance(node, ast.FunctionDef) and not hasattr(node, '_in_class'):
        if node.col_offset == 0:
            args = [a.arg for a in node.args.args]
            print(f'FUNCTION: {node.name}({', '.join(args)})')
